         * Migrate bindings from FLIP_OR_ANSWER_RECOMMENDED / FLIP_OR_ANSWER_BETTER_THAN_RECOMMENDED
         * to the equivalent answer buttons.
         */
        internal class MigrateRecommendedAnswerBindings : PreferenceUpgrade(12) {
            override fun upgrade(preferences: SharedPreferences) {
                migrate(preferences, "binding_FLIP_OR_ANSWER_RECOMMENDED", ViewerCommand.FLIP_OR_ANSWER_EASE3)
                migrate(preferences, "binding_FLIP_OR_ANSWER_BETTER_THAN_RECOMMENDED", ViewerCommand.FLIP_OR_ANSWER_EASE4)
            }

            private fun migrate(preferences: SharedPreferences, oldKey: String, newCommand: ViewerCommand) {
                if (!preferences.contains(oldKey)) {
                    return
                }

                val oldBindings = MappableBinding.fromPreferenceString(preferences.getString(oldKey, null))
                if (oldBindings.isEmpty()) {
                    preferences.edit { remove(oldKey) }
                    return
                }

                val currentValue = preferences.getString(newCommand.preferenceKey, null)
                val newBindings = if (currentValue != null) {
                    MappableBinding.fromPreferenceString(currentValue)
                } else {
                    newCommand.defaultValue.toMutableList()
                }

                var changed = false
                for (binding in oldBindings) {
                    if (!newBindings.contains(binding)) {
                        newBindings.add(binding)
                        changed = true
                    }
                }

                preferences.edit {
                    if (changed && currentValue == null) {
                        // Only persist if we're extending the default bindings
                        putString(newCommand.preferenceKey, newBindings.toPreferenceString())
                    } else if (changed) {
